(self.webpackChunkcheatsheet=self.webpackChunkcheatsheet||[]).push([[3143],{8454:(n,t,e)=>{"use strict";e.r(t),e.d(t,{data:()=>a});const a={key:"v-17afa7cf",path:"/python/io/",title:"รับและส่งข้อมูล",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:2,title:"การรับ Input",slug:"การรับ-input",children:[]},{level:2,title:"การส่ง Output",slug:"การส่ง-output",children:[{level:3,title:"วิธีการแสดง output",slug:"วิธีการแสดง-output",children:[]}]}],filePathRelative:"python/io/README.md",git:{updatedTime:162676698e4,contributors:[]}}},4837:(n,t,e)=>{"use strict";e.r(t),e.d(t,{default:()=>s});const a=(0,e(6252).uE)('<h1 id="รับและส่งข้อมูล" tabindex="-1"><a class="header-anchor" href="#รับและส่งข้อมูล" aria-hidden="true">#</a> รับและส่งข้อมูล</h1><p>เรื่องแรกที่เราจะเรียนเป็นสี่งแรกในการเรียนการเขียนโปรแกรม นั่นก็คือเรื่องการ Input และ Output ของโปรแกรม<br> Input และ Output เป็นเรื่องสำคัญต่อการทำโปรแกรม เพราะหากว่าเราไม่มี น้องจะรู้หรือเปล่า ว่าโปรแกรมมันทำงานได้ถูกต้องแล้วหรือไม่<br> ดังนั้น ทุกโปรแกรมจึงควรมีทั้ง Input และ Output เสมอ</p><p>แต่ก่อนที่จะให้น้องๆไปแตะเรื่อง input และ output ก็ต้องสอนน้องๆประกาศตัวแปรกันก่อน</p><h2 id="การรับ-input" tabindex="-1"><a class="header-anchor" href="#การรับ-input" aria-hidden="true">#</a> การรับ Input</h2><p>Input หมายถึงสิ่งที่ได้รับเข้ามา ในที่นี้คือโปรแกรมนั้นจะรับค่าอะไรมาซักอย่าง เพื่อที่จะให้นำไปใช้ในโปรแกรมของจริง<br> โดยในภาษา Python นั้นจะใช้ฟังก์ชัน <code>input()</code> เพื่อทำการรับ input เข้ามาสู่ระบบ</p><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>การใช้ input() นั้น ทำให้ข้อมูลที่ได้รับเข้ามา จะถูกเปลี่ยนไปเป็นประเภท string ทั้งหมด เพื่อป้องกันการเก็บข้อมูลผิดประเภทนั่นเอง<br> ถ้าหากต้องการเปลี่ยนประเภทของ input เป็นอย่างต่างๆ (เช่น float, boolean, integer) <br> ก็จำเป็นที่จะต้องทำการ <a href="">Data type Casting</a> โดยจะสอนวิธีการเปลี่ยนประเภทตัวแปรในขั้นตอนต่อๆไป</p></div><p>ตัวอย่างการรับ input ในภาษา Python</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token builtin">input</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>แต่รับมาแล้ว ใครจะจำค่าที่ได้รับ input มาหล่ะ<br> ดังนั้นจึงต้องมีตัวแปรมาจัดเก็บข้อมูลครับ</p><p>ตัวอย่างเช่น</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>kumamon <span class="token operator">=</span> <span class="token builtin">input</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>โดยในโค้ดด้านบนนั้น ตัวแปร <code>kumamon</code> ก็จะมีค่าที่ได้รับมาจากฟังก์ชั่น <code>input()</code> อยู่</p><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>การรับ input นั้น จะรับค่าตั้งแต่ตัวอักษรแรก จนสุดบรรทัด นั่นหมายความว่า หากมีการให้ input มาหลายบรรทัด เช่น</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>My\nname\nis\nKumamon\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>ก็จะรับ input มาเพียงบรรทัดแรกเท่านั้น (นั่นก็คือ &quot;My&quot; เท่านั้น)</p></div><h2 id="การส่ง-output" tabindex="-1"><a class="header-anchor" href="#การส่ง-output" aria-hidden="true">#</a> การส่ง Output</h2><p>Output นั้นหมายถึงการเอาอะไรออกไป<br> โดยปกติแล้ว การส่ง output นั้น ก็จะมี 2 ประเภทหลักๆ นั่นคือ</p><ol><li>แสดง output ออกบนหน้าจอ</li><li>โยน output ไปยังฟังกชันอื่น (เป็นการคืนผลลัพท์ (return) หรือเพื่อไปเป็น input ของอีกฟังก์ชั่นนึง)</li></ol><p>ใน lecture นี้ พี่มงจะสอนเพียงการแสดง output ออกบนหน้าจอเท่านั้น<br> หากว่าน้องต้องการศึกษา output ประเภทโยนให้ฟังก์ชันอื่นๆ สามารถเข้าไปดูได้ที่ lecture ถัดไป (เรื่อง Functions)</p><h3 id="วิธีการแสดง-output" tabindex="-1"><a class="header-anchor" href="#วิธีการแสดง-output" aria-hidden="true">#</a> วิธีการแสดง output</h3><p>สามารถใช้ฟังก์ชัน <code>print()</code> เพื่อให้แสดงผลลัพท์บนหน้าจอผลลัพท์</p><p>ตัวอย่างการใช้ <code>print()</code></p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Hello, my name is Kumamon&quot;</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>หากเอาโปรแกรมไปรันแล้ว น้องๆก็จะเห็น string ที่เขียนว่า &quot;Hello, my name is Kumamon&quot; บนหน้าจอ shell ของ Python</p><p>การแสดง output นั้น ไม่จำเป็นที่จะต้องเป็น string (แบบตัวอย่างด้านบน) เสมอไป<br> น้องสามารถให้โปรแกรมแสดงค่าข้อมูลที่อยู่ภายในตัวแปรก็ได้</p><p>ตัวอย่างเช่น</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>player1 <span class="token operator">=</span> <span class="token string">&quot;Kumamon&quot;</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span>player1<span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>ในโค้ดด้านบนนั้น บ่งบอกถึงการเก็บ string ที่เขียนว่า &quot;Kumamon&quot; ลงบนตัวแปร <code>player1</code> และก็ได้ทำการ <code>print()</code> ตัวแปรนั้นออกมาเพื่อแสดงบนหน้าจอ</p>',26),s={render:function(n,t){return a}}}}]);